function makeRng(baseSeed, entityId, tag, tsMs) {
    const key = String(baseSeed) + ':' + String(entityId) + ':' + String(tag) + ':' + String(tsMs);
    const seedHex = crypto.createHash('sha256').update(key).digest('hex').slice(0, 16);
    return seedrandom.alea(seedHex);
}
function uniform(rng, min, max) { return min + (max - min) * rng(); }
function normal(rng, mean, stddev) {
    let u = 0; let v = 0;
    while (u === 0) u = rng();
    while (v === 0) v = rng();
    const z = Math.sqrt(-2 * Math.log(u)) * Math.cos(2 * Math.PI * v);
    return mean + stddev * z;
}
function isWeekend(d) { const w = d.getUTCDay(); return w === 0 || w === 6; }

const WEEKDAY = [0.3, 0.28, 0.25, 0.25, 0.27, 0.35, 0.55, 0.75, 0.9, 0.95, 1.0, 0.98, 0.85, 0.92, 0.98, 0.95, 0.88, 0.7, 0.5, 0.45, 0.4, 0.38, 0.35, 0.32];
const WEEKEND = [0.2, 0.18, 0.16, 0.15, 0.15, 0.18, 0.25, 0.35, 0.45, 0.5, 0.55, 0.52, 0.45, 0.48, 0.5, 0.48, 0.42, 0.35, 0.3, 0.28, 0.25, 0.23, 0.22, 0.21];

const DEFAULT_CFG = {
    meter_id: 'meter-default',
    base_power_kw: 10,
    peak_power_kw: 50,
    nominal_voltage_v: 230,
    voltage_variance_pct: 5,
    nominal_frequency_hz: 50,
    frequency_variance_hz: 0.05,
    power_factor_min: 0.95,
    power_factor_max: 0.99,
    initial_energy_kwh: 0
};

function loadFactor(date) {
    const curve = isWeekend(date) ? WEEKEND : WEEKDAY;
    const hour = date.getUTCHours();
    const minute = date.getUTCMinutes();
    const cur = curve[hour];
    const nxt = curve[(hour + 1) % 24];
    return cur + (nxt - cur) * (minute / 60);
}

function loadFactorWithNoise(date, rng) {
    const base = loadFactor(date);
    const noise = normal(rng, 0, 0.05);
    return Math.max(0.1, Math.min(1.0, base + noise));
}

function distributePower(totalW, rng, imbalance) {
    const share = totalW / 3;
    const i1 = uniform(rng, -imbalance, imbalance);
    const i2 = uniform(rng, -imbalance, imbalance);
    const i3 = -(i1 + i2);
    return [share * (1 + i1), share * (1 + i2), share * (1 + i3)];
}

function cumulativeEnergy(date, cfg) {
    const ref = Date.UTC(date.getUTCFullYear(), 0, 1, 0, 0, 0);
    const ms = date.getTime();
    if (ms <= ref) return cfg.initial_energy_kwh;
    const totalHours = (ms - ref) / 3600000;
    const avgLoadFactor = 0.53;
    const avgPowerKw = cfg.base_power_kw + (cfg.peak_power_kw - cfg.base_power_kw) * avgLoadFactor;
    return cfg.initial_energy_kwh + avgPowerKw * totalHours;
}

function generateMeter(payload) {
    const baseSeed = (typeof payload.base_seed === 'number') ? payload.base_seed : 12345;
    const entityId = payload.entity_id || 'meter-default';
    const tsMs = (typeof payload.timestamp_ms === 'number') ? payload.timestamp_ms : 0;
    const isoTs = payload.timestamp || new Date(tsMs).toISOString();
    const siteId = payload.site_id || '';
    const cfg = Object.assign({}, DEFAULT_CFG, payload.config || {});
    const mode = payload.mode || 'normal';
    const date = new Date(isoTs);
    const rng = makeRng(baseSeed, entityId, 'meter', tsMs);

    const lf = loadFactorWithNoise(date, rng);
    let totalKw = cfg.base_power_kw + (cfg.peak_power_kw - cfg.base_power_kw) * lf;
    if (mode === 'event') {
        const minOfDay = date.getUTCHours() * 60 + date.getUTCMinutes();
        if (minOfDay >= 600 && minOfDay < 620) totalKw *= 2.0;
    }
    const totalW = totalKw * 1000;

    const [p1, p2, p3] = distributePower(totalW, rng, 0.08);
    const vVar = cfg.nominal_voltage_v * (cfg.voltage_variance_pct / 100);
    const v1 = cfg.nominal_voltage_v + uniform(rng, -vVar, vVar);
    const v2 = cfg.nominal_voltage_v + uniform(rng, -vVar, vVar);
    const v3 = cfg.nominal_voltage_v + uniform(rng, -vVar, vVar);
    const pf = uniform(rng, cfg.power_factor_min, cfg.power_factor_max);
    const i1 = v1 > 0 ? p1 / (v1 * pf) : 0;
    const i2 = v2 > 0 ? p2 / (v2 * pf) : 0;
    const i3 = v3 > 0 ? p3 / (v3 * pf) : 0;
    const freq = cfg.nominal_frequency_hz + uniform(rng, -cfg.frequency_variance_hz, cfg.frequency_variance_hz);
    const energy = cumulativeEnergy(date, cfg);

    return {
        site_id: siteId,
        timestamp: isoTs,
        meter_id: cfg.meter_id || entityId,
        readings: {
            active_power_l1_w: p1, active_power_l2_w: p2, active_power_l3_w: p3,
            voltage_l1_v: v1, voltage_l2_v: v2, voltage_l3_v: v3,
            current_l1_a: i1, current_l2_a: i2, current_l3_a: i3,
            power_factor: pf, frequency_hz: freq, total_energy_kwh: energy
        }
    };
}

msg.payload = generateMeter(msg.payload || {});
return msg;
